INSERT INTO "public"."gc_faq" ("id", "question", "answer", "createdAt", "updatedAt", "createdBy", "updatedBy", "deletedAt") VALUES
(120, 'What resources does 1851 Franchise offer for potential franchisees?', '1851 Franchise offers a variety of resources, including articles, guides, webinars, and masterclasses on topics such as how to buy a franchise, evaluating franchise opportunities, financing options, and growing a franchise. They also provide access to franchise brokers and consultants who can offer personalized advice.', '2025-01-27 12:02:46.722754', '2025-01-27 12:02:46.722754', 179, 179, NULL);
INSERT INTO "public"."gc_faq" ("id", "question", "answer", "createdAt", "updatedAt", "createdBy", "updatedBy", "deletedAt") VALUES
(121, 'Autem omnis ipsam quas repudiandae odio ipsum facilis in.', 'Maiores a esse rerum tempora consequuntur aperiam minus.', '2025-01-27 12:09:48.298312', '2025-01-27 12:09:48.298312', 179, 179, NULL);
INSERT INTO "public"."gc_faq" ("id", "question", "answer", "createdAt", "updatedAt", "createdBy", "updatedBy", "deletedAt") VALUES
(122, 'How can I stay updated on franchise news and trends?', 'You can stay updated on franchise news and trends by subscribing to 1851 Franchise''s newsletter, following their social media channels, and attending their events and webinars. They offer regular updates on industry developments, success stories, and new franchise opportunities.', '2025-01-28 06:07:29.110265', '2025-01-28 06:07:29.110265', 179, 179, NULL),
(123, 'What are the potential earnings from owning a franchise?', 'Potential earnings from owning a franchise can vary widely depending on the franchise brand, location, and individual effort. 1851 Franchise provides information on average earnings for different franchise brands and tips on how to maximize your earnings potential.', '2025-01-28 06:10:02.290089', '2025-01-28 06:10:02.290089', 179, 179, NULL),
(124, 'How do I choose the right franchise for me?', 'Choosing the right franchise involves assessing your interests, skills, and financial goals. 1851 Franchise offers tools and resources to help you identify your strengths and preferences, evaluate different franchise opportunities, and make an informed decision.', '2025-01-28 06:10:26.562643', '2025-01-28 06:10:26.562643', 179, 179, NULL),
(125, 'What kind of support can I expect from a franchisor?', 'Support from a franchisor can vary, but typically includes initial training, ongoing support, marketing assistance, and access to a network of other franchisees. 1851 Franchise provides information on what to look for in terms of support and how to make the most of it.', '2025-01-28 06:10:41.945839', '2025-01-28 06:10:41.945839', 179, 179, NULL),
(126, 'How can I finance the purchase of a franchise?', '1851 Franchise offers resources on how to finance the purchase of a franchise, including information on loans, grants, and other funding options. They also provide guidance on preparing a business plan and presenting it to lenders to secure financing.', '2025-01-28 06:11:03.238306', '2025-01-28 06:11:03.238306', 179, 179, NULL),
(127, 'What is the Franchise Disclosure Document (FDD), and why is it important?', 'The Franchise Disclosure Document (FDD) is a legal document that franchisors are required to provide to potential franchisees. It contains detailed information about the franchise, including its history, financial performance, legal obligations, and more. Reviewing the FDD is crucial to understanding the risks and benefits of investing in a particular franchise.', '2025-01-28 06:11:30.190545', '2025-01-28 06:11:30.190545', 179, 179, NULL),
(128, 'How do I evaluate a franchise opportunity?', 'To evaluate a franchise opportunity, you can use the resources provided by 1851 Franchise, such as their guide on evaluating franchise opportunities. This guide covers key factors to consider, such as the franchise''s track record, support and training provided, initial investment requirements, and potential earnings.', '2025-01-28 06:11:50.12028', '2025-01-28 06:11:50.12028', 179, 179, NULL),
(129, 'What resources does 1851 Franchise offer for potential franchisees?', '1851 Franchise offers a variety of resources, including articles, guides, webinars, and masterclasses on topics such as how to buy a franchise, evaluating franchise opportunities, financing options, and growing a franchise. They also provide access to franchise brokers and consultants who can offer personalized advice.', '2025-01-28 06:12:10.891211', '2025-01-28 06:12:10.891211', 179, 179, NULL),
(130, 'How can I find franchise opportunities on 1851 Franchise?', 'You can explore franchise opportunities by visiting the 1851 Franchise website and browsing through their extensive directory of franchise brands. You can filter opportunities based on industry, investment range, and other criteria to find the best match for your interests and goals.', '2025-01-28 06:12:34.696279', '2025-01-28 06:12:34.696279', 179, 179, NULL),
(131, 'What is 1851 Franchise?', '1851 Franchise is a comprehensive resource for franchise opportunities, news, and resources. It provides information on various franchise brands, industry trends, and investment ranges.', '2025-01-28 06:12:57.030729', '2025-01-28 06:12:57.030729', 179, 179, NULL),
(132, 'How can I stay updated on franchise news and trends?', 'You can stay updated on franchise news and trends by subscribing to 1851 Franchise''s newsletter, following their social media channels, and attending their events and webinars. They offer regular updates on industry developments, success stories, and new franchise opportunities.', '2025-01-28 06:13:33.413279', '2025-01-28 06:13:33.413279', 179, 179, NULL),
(133, 'What are the potential earnings from owning a franchise?', 'Potential earnings from owning a franchise can vary widely depending on the franchise brand, location, and individual effort. 1851 Franchise provides information on average earnings for different franchise brands and tips on how to maximize your earnings potential.', '2025-01-28 06:13:52.259372', '2025-01-28 06:17:00.639434', 179, 179, '2025-01-28 06:17:00.639434'),
