-- This script only contains the table creation statements and does not fully represent the table in the database. Do not use it as a backup.

-- Sequence and defined type
CREATE SEQUENCE IF NOT EXISTS gc_faq_id_seq;

-- Table Definition
CREATE TABLE "public"."gc_faq" (
    "id" int4 NOT NULL DEFAULT nextval('gc_faq_id_seq'::regclass),
    "question" varchar NOT NULL,
    "answer" varchar NOT NULL,
    "createdAt" timestamp NOT NULL DEFAULT now(),
    "updatedAt" timestamp NOT NULL DEFAULT now(),
    "createdBy" int4 NOT NULL,
    "updatedBy" int4 NOT NULL,
    "deletedAt" timestamp,
    PRIMARY KEY ("id")
);


-- Indices
CREATE UNIQUE INDEX "PK_bf1590eaf9cabcb66056b9e653e" ON public.gc_faq USING btree (id);

